const Q_ACCOUNTS_2023_MODEL_II=[{"id": "objective>Accounts>2023 Model II>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following concepts recognizes the principle of double entry?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">accrual</div>", "<div style=\"font-family:Cambria;font-size:17px;\">business entity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dual aspect</div>", "<div style=\"font-family:Cambria;font-size:17px;\">going concern</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dual aspect concept ensures the mathematical accuracy of all records. It states that there are two aspects of accounting: one debit and one credit.</div>", "topic": "PRINCIPLE OF DOUBLE ENTRY : MEANING AND APPLICATION"}, {"id": "objective>Accounts>2023 Model II>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Income and Expenditure account is the same as the --------- of a sole trader</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">balance sheet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash book</div>", "<div style=\"font-family:Cambria;font-size:17px;\">profit and loss account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trading account</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The income and expenditure account shows the summary of revenue and running cost of a non-profit making organization. It follows the same principles as the profit and loss account of a trading concern.</div>", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS"}, {"id": "objective>Accounts>2023 Model II>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Current assets are shown in the balance sheet in order of permanence as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">debtors, stock, bank and cash</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debtors, stock, cash and bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stock, bank, debtors and cash</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stock, debtors, bank and cash</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The current assets are usually listed on the balance sheet in the following order: <br/> - inventory (stock) <br/> -  account receivables  e.g debtors <br/> - marketables securities <br/> - cash and cash equivalent</div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET"}, {"id": "objective>Accounts>2023 Model II>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>The following was extracted from the books of MEGA COMPANY NIG. LTD</strong> <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">₦</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Trade debtors</td><td style=\"border:1px solid black;text-align:center;\"> 350,000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Fixtures and fittings</td><td style=\"border:1px solid black;text-align:center;\"> 600,000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Cash at bank</td><td style=\"border:1px solid black;text-align:center;\"> 25,000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Cash in hand</td><td style=\"border:1px solid black;text-align:center;\"> 5,500</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Trade creditors</td><td style=\"border:1px solid black;text-align:center;\"> 116,500</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Bank overdraft</td><td style=\"border:1px solid black;text-align:center;\"> 7,500</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Building</td><td style=\"border:1px solid black;text-align:center;\"> 950,000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Motor van</td><td style=\"border:1px solid black;text-align:center;\"> 35,000</td></tr></table></div> <br/> The working capital of the company is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦565,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦280,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦256,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦156,000</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Working capital = Current Assets - Current Liabilites <br/> = (350,000 + 25,000 + 5,500) - ( 116,500 + 7,500) <br/> = 380,500 - 124, 000 <br/> = ₦256,500</div>", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES"}, {"id": "objective>Accounts>2023 Model II>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is <strong>not</strong> an advantage of control account?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">difficulty in committing fraud</div>", "<div style=\"font-family:Cambria;font-size:17px;\">helps in locating errors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">helps to determine profit and loss</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it can be used to detect missing figure</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The uses of control account are: <br/> - location of errors <br/> - prevention of fraud <br/> - preparation of interim final account <br/> - saves time <br/> - easy detection of missing figures</div>", "topic": "CONTROL ACCOUNTS : INTRODUCTION, ADVANTAGES OF CONTROL ACCOUNTS"}, {"id": "objective>Accounts>2023 Model II>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is <strong>not</strong> charged to manufacturing account?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">direct expenses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">distribution expenses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">factory wages</div>", "<div style=\"font-family:Cambria;font-size:17px;\">raw materials</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Distribution expenses covers the cost of warehousing, transport, material handling and control of finished goods from the moment. It is not charged to manufacturing account.</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2023 Model II>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The document which is legal charter of a company that defines the limits of a company's field of operation is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">articles of association</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equity share certificate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">memorandum of association</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prospectus</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Memorandum of Association (MOA) of a company defines the constitution and the scope of powers of the company.</div>", "topic": "COMPANY ACCOUNT : FORMATION OF COMPANY"}, {"id": "objective>Accounts>2023 Model II>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">₦</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Manufacturing wages</td><td style=\"border:1px solid black;text-align:center;\"> 42,000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Factory rent</td><td style=\"border:1px solid black;text-align:center;\"> 880</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Raw materials: Stock 1/1/16</td><td style=\"border:1px solid black;text-align:center;\"> 1,000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchases</td><td style=\"border:1px solid black;text-align:center;\"> 16,000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock 31/12/16</td><td style=\"border:1px solid black;text-align:center;\"> 1,400</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Depreciation of Plants and Machinery</td><td style=\"border:1px solid black;text-align:center;\"> 800</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Royalties</td><td style=\"border:1px solid black;text-align:center;\"> 300</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Indirect wages</td><td style=\"border:1px solid black;text-align:center;\"> 18,000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">General indirect expenses</td><td style=\"border:1px solid black;text-align:center;\"> 620</td></tr></table></div> <br/>  <br/> Calculate the cost of raw materials consumed</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦42,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦20,300</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦17,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦15,600</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cost of raw materials consumed = 1000 + 16000 - 1400 <br/> = ₦ = 15600</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2023 Model II>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">₦</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Manufacturing wages</td><td style=\"border:1px solid black;text-align:center;\"> 42,000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Factory rent</td><td style=\"border:1px solid black;text-align:center;\"> 880</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Raw materials: Stock 1/1/16</td><td style=\"border:1px solid black;text-align:center;\"> 1,000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchases</td><td style=\"border:1px solid black;text-align:center;\"> 16,000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock 31/12/16</td><td style=\"border:1px solid black;text-align:center;\"> 1,400</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Depreciation of Plants and Machinery</td><td style=\"border:1px solid black;text-align:center;\"> 800</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Royalties</td><td style=\"border:1px solid black;text-align:center;\"> 300</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Indirect wages</td><td style=\"border:1px solid black;text-align:center;\"> 18,000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">General indirect expenses</td><td style=\"border:1px solid black;text-align:center;\"> 620</td></tr></table></div> <br/> The prime cost is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦78,200</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦57,900</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦45,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦42,000</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Prime cost = Cost of raw materials consumed + Manufacturing wages + Royalties <br/> = 15600 + 42000 + 300 <br/> = ₦57,900</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2023 Model II>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">₦</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Manufacturing wages</td><td style=\"border:1px solid black;text-align:center;\"> 42,000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Factory rent</td><td style=\"border:1px solid black;text-align:center;\"> 880</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Raw materials: Stock 1/1/16</td><td style=\"border:1px solid black;text-align:center;\"> 1,000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Purchases</td><td style=\"border:1px solid black;text-align:center;\"> 16,000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Stock 31/12/16</td><td style=\"border:1px solid black;text-align:center;\"> 1,400</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Depreciation of Plants and Machinery</td><td style=\"border:1px solid black;text-align:center;\"> 800</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Royalties</td><td style=\"border:1px solid black;text-align:center;\"> 300</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Indirect wages</td><td style=\"border:1px solid black;text-align:center;\"> 18,000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">General indirect expenses</td><td style=\"border:1px solid black;text-align:center;\"> 620</td></tr></table></div> <br/> What is the value of the indirect manufacturing cost?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦57,900</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦23,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦20,300</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦18,200</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Indirect cost = 880 + 800 + 18000 + 620 <br/>  <br/>  <br/> = ₦20300</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2023 Model II>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Profit expressed in relation to cost of goods sold is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cost price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">margin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mark -up</div>", "<div style=\"font-family:Cambria;font-size:17px;\">turnover</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mark up is when profit is expressed as a percentage of cost price i.e cost of goods sold.</div>", "topic": "ACCOUNTING RATIO ( 1) : MARK UP AND MARGIN"}, {"id": "objective>Accounts>2023 Model II>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When the goods are sold on credit to a buyer, the account receivable account will be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">debited</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contra entry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">credited</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debit and credit</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When the goods are sold on credit to a buyer, the account receivable account debits, increasing the company's assets as the amount is receivable from the third party. The corresponding credit will be in the sales account, increasing the company's revenue. </div>", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS"}, {"id": "objective>Accounts>2023 Model II>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In company account, dividend payments are effected in which of the following accounts?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">appropriation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">current</div>", "<div style=\"font-family:Cambria;font-size:17px;\">realization</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In company accounting, dividend payments are effected in the appropriation account. The appropriation account is a part of the profit and loss account where the net profit is appropriated or distributed among various heads like dividends, general reserve, etc.</div>", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES"}, {"id": "objective>Accounts>2023 Model II>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Shares are said to be authorized when they are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">called up</div>", "<div style=\"font-family:Cambria;font-size:17px;\">offered for sale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">paid -up</div>", "<div style=\"font-family:Cambria;font-size:17px;\">subscribed</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Authorized shares are defined as the maximum number of shares that a company is legally allowed to issue to investors as per its own determinations</div>", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES"}, {"id": "objective>Accounts>2023 Model II>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following expenses is <strong>not</strong> apportioned in proportion to turnover?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">carriage outwards</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">discount allowed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rent</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rent is typically not apportioned in proportion to turnover. Rent is a fixed cost, meaning it does not change with the level of output or sales (turnover). It is usually apportioned based on the space occupied by each department or activity, not on the level of sales or turnover. On the other hand, carriage outwards, commission, and discount allowed are variable costs that change with the level of sales or turnover, so they are typically apportioned in proportion to turnover.</div>", "topic": "DEPARTMENTAL ACCOUNT : METHODS OF APPORTIONMENT OF EXPENSES"}, {"id": "objective>Accounts>2023 Model II>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>Larry Limited</strong> has 4,000,000 ordinary shares of 50k each and 150,000 5% prefrence shares of ₦1 each fully paid. <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">₦</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Net profit for the year</td><td style=\"border:1px solid black;text-align:center;\">90,000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Interim dividends paid:</td><td style=\"border:1px solid black;text-align:center;\"></td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Ordinary shares</td><td style=\"border:1px solid black;text-align:center;\"> 25,000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Profit and loss appropriation b/f</td><td style=\"border:1px solid black;text-align:center;\"> 10,000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Goodwill written off</td><td style=\"border:1px solid black;text-align:center;\"> 1,000</td></tr></table></div> <br/>  <br/> The amount of preference shares dividends payable at the end of the year is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦7,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦25,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦20,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦10,000</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The amount of preference shares dividends payable at the end of the year is <br/>  <br/>                        <br/> = 5%  x 150,000 <br/>  <br/>  <br/> = ₦7,500</div>", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES"}, {"id": "objective>Accounts>2023 Model II>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong>Larry Limited</strong> has 4,000,000 ordinary shares of 50k each and 150,000 5% prefrence shares of ₦1 each fully paid. <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">₦</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Net profit for the year</td><td style=\"border:1px solid black;text-align:center;\">90,000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Interim dividends paid:</td><td style=\"border:1px solid black;text-align:center;\"></td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Ordinary shares</td><td style=\"border:1px solid black;text-align:center;\"> 25,000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Profit and loss appropriation b/f</td><td style=\"border:1px solid black;text-align:center;\"> 10,000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Goodwill written off</td><td style=\"border:1px solid black;text-align:center;\"> 1,000</td></tr></table></div> <br/> At the end of the period, what is the balance of the profit and loss appropriation account?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦100,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦90,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦66,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦74,000</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Balance c/d = net profit + profit and loss - ( goodwill + ordinary share + preference share) <br/>  = (90,000 + 10,000) - ( 1000 + 25000 + 7500) <br/> = 100,000 - 33500 <br/> = ₦66500</div>", "topic": "COMPANY ACCOUNT : FINAL ACCOUNTS OF A LIMITED COMPANY AND TERMINOLOGIES"}, {"id": "objective>Accounts>2023 Model II>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Factory overheads are also known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">direct expenses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">direct labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">direct manufacturing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">indirect cost</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Factory overhead are costs necessary for production which are not directly traceable to a specific quantity of physical units e,g factory rent, depreciation, fuel,  indirect wages etc.</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2023 Model II>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is charged to trading account?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">carriage inwards</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carriage outwards</div>", "<div style=\"font-family:Cambria;font-size:17px;\">discount allowed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rent</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Carriage inwards is the cost of transportation charged on goods purchased. It must be added to the goods purchased, hence it is debited to trading account.</div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES"}, {"id": "objective>Accounts>2023 Model II>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>Dairo</strong> and <strong>Segun</strong> are in partnership sharing profits and losses in the ratio 2:3 respectively. The information below relates to their business for the year ended 31st December, 2018. <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Drawings:</td><td style=\"border:1px solid black;text-align:center;\"> ₦</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Dairo</td><td style=\"border:1px solid black;text-align:center;\"> 12000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Segun</td><td style=\"border:1px solid black;text-align:center;\"> 18000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Capital:</td><td style=\"border:1px solid black;text-align:center;\"></td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Dairo</td><td style=\"border:1px solid black;text-align:center;\"> 120000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Segun</td><td style=\"border:1px solid black;text-align:center;\"> 60000</td></tr></table></div> <br/>  <br/> - Interest on drawings 10% <br/>  <br/> - Interest on capital 5% <br/>  <br/> - Profit for the year ₦36,000 <br/>  <br/> - Salary: Segun ₦10,000 <br/>  <br/> The interest on Dairo's drawings is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦1,800</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦1,600</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦1,400</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦1,200</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The interest on Dairo's drawings is calculated by multiplying the amount of his drawings (₦12,000) by the interest rate on drawings (10%). This gives us ₦1,200.</div>", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR"}, {"id": "objective>Accounts>2023 Model II>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong>Dairo</strong> and <strong>Segun</strong> are in partnership sharing profits and losses in the ratio 2:3 respectively. The information below relates to their business for the year ended 31st December, 2018. <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Drawings:</td><td style=\"border:1px solid black;text-align:center;\"> ₦</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Dairo</td><td style=\"border:1px solid black;text-align:center;\"> 12000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Segun</td><td style=\"border:1px solid black;text-align:center;\"> 18000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Capital:</td><td style=\"border:1px solid black;text-align:center;\"></td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Dairo</td><td style=\"border:1px solid black;text-align:center;\"> 120000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Segun</td><td style=\"border:1px solid black;text-align:center;\"> 60000</td></tr></table></div> <br/>  <br/> - Interest on drawings 10% <br/>  <br/> - Interest on capital 5% <br/>  <br/> - Profit for the year ₦36,000 <br/>  <br/> - Salary: Segun ₦10,000 <br/> Segun's share of profit is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦12,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦21,400</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦16,400</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦14,600</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Interest on drawings = 10% <br/> - Dairo = 10%  x 12,0000 <br/> = ₦1200 <br/> - Segun = 10%  x 18,000 <br/> = ₦1800 <br/>  <br/> Interest on capital = 5% <br/> - Dairo = 5%  x 120,000 <br/>  = ₦6,000 <br/> - Segun = 5%  x 60,000 <br/> =₦3,000 <br/>  <br/> Salary: segun = ₦10,000 <br/>  <br/> Segun's share of profit = (Net profit +  int on drawings) - ( int on capital + segun salary ) <br/> = (36000 + 1200 + 1800) - ( 6000 + 3000 + 10000) <br/> = 39000 - 19000 <br/> = 20,000 <br/>  <br/> Total ratio = 2+ 3 <br/> = 5 <br/> Therefore, Segun share of profit =  3 /5 x 20000 <br/> = ₦12,000</div>", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR"}, {"id": "objective>Accounts>2023 Model II>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The purchases ledger control account is also known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bill payable control account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">creditors control account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">credit purchase control account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total purchase</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The purchases ledger control account is also known as the creditors control account. This account is used in a business's accounting to record the total amount owed to suppliers for purchases made on credit. It is a summary account that reflects the total amount payable to all suppliers.</div>", "topic": "CONTROL ACCOUNTS : PURCHASES LEDGER CONTROL ACCOUNT"}, {"id": "objective>Accounts>2023 Model II>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Another name for control accounts is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">creditors' account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debtors' account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">purchases ledger</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total account</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Contrl account is also known as self balancing ledger of total control account.</div>", "topic": "CONTROL ACCOUNTS : INTRODUCTION, ADVANTAGES OF CONTROL ACCOUNTS"}, {"id": "objective>Accounts>2023 Model II>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the absence of a partnership agreement, a loan given to the partnership by a partner attracts interest of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">15%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10%</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">7</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">%</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\">5%</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Where there is no agreement betwen the partners, the following must applied: <br/> - there is no interest on capital <br/> - no salary for partners acting in the business <br/> - no interest to be charged on drawings <br/> - profit and loss are to be shared equally <br/> - 5% interest a year on loans made by partners in excess of the agreed capitals <br/> - no partners may introduce a new person without the consent of all existing partners</div>", "topic": "DISSOLUTION OF PARTNERSHIP ACCOUNT : INTRODUCTION AND RULES FOR DISTRIBUTING OF ASSSETS"}, {"id": "objective>Accounts>2023 Model II>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Accounting term used to describe a partnership firm that stops operation and disposes its assets is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Amortization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dissolution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Realization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Revaluation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dissolution of partnership is the process whereby a partnership is automatically dissolved or brought to an end by the happenings of any event which makes it unlawful to carry on the business.</div>", "topic": "DISSOLUTION OF PARTNERSHIP ACCOUNT : INTRODUCTION AND RULES FOR DISTRIBUTING OF ASSSETS"}, {"id": "objective>Accounts>2023 Model II>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is prepared to ascertain the trader's capital under incomplete records?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">income statement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">statement of affairs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">statement of capital and liabilites</div>", "<div style=\"font-family:Cambria;font-size:17px;\">statement of complete records</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The statement of affairs is prepared to ascertain both the opening and closing capital of the business. The statement of affairs is smiliar to the balance sheet.</div>", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : STATEMENT OF AFFAIRS"}, {"id": "objective>Accounts>2023 Model II>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The assumption that a business will continue to exist into the foreseeanle future is recognized by a concept called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">business entity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">going concern</div>", "<div style=\"font-family:Cambria;font-size:17px;\">historical cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">matching</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The going concern concept states that a business will continue to operate for an indefinte period of time or perpectual existence.</div>", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS"}, {"id": "objective>Accounts>2023 Model II>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Danladi Bako's Statement of Affairs as at 30/06/17 <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">₦</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">₦</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Capital</td><td style=\"border:1px solid black;text-align:center;\"> ??</td><td style=\"border:1px solid black;text-align:center;\">Fixtures and fittings</td><td style=\"border:1px solid black;text-align:center;\"> 4,000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">Stock</td><td style=\"border:1px solid black;text-align:center;\"> 20,500</td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">Sundry debtors</td><td style=\"border:1px solid black;text-align:center;\">40,000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Creditors</td><td style=\"border:1px solid black;text-align:center;\"><span style=\"text-decoration:underline;\"> 18,000 </span></td><td style=\"border:1px solid black;text-align:center;\">Bank</td><td style=\"border:1px solid black;text-align:center;\"><span style=\"text-decoration:underline;\"> ?? </span></td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">78,650</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">78,650</td></tr></table></div> <br/>  <br/> What is his bank balance as at 30/06/17?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦65,150</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦18,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦15,300</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦14,150</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bank balance = 78,650 - ( 4000 + 20500 + 40000) <br/> = 78650 - 64500 <br/> = ₦14,150</div>", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : STATEMENT OF AFFAIRS"}, {"id": "objective>Accounts>2023 Model II>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Danladi Bako's Statement of Affairs as at 30/06/17 <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">₦</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">₦</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Capital</td><td style=\"border:1px solid black;text-align:center;\"> ??</td><td style=\"border:1px solid black;text-align:center;\">Fixtures and fittings</td><td style=\"border:1px solid black;text-align:center;\"> 4,000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">Stock</td><td style=\"border:1px solid black;text-align:center;\"> 20,500</td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">Sundry debtors</td><td style=\"border:1px solid black;text-align:center;\">40,000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Creditors</td><td style=\"border:1px solid black;text-align:center;\"><span style=\"text-decoration:underline;\"> 18,000 </span></td><td style=\"border:1px solid black;text-align:center;\">Bank</td><td style=\"border:1px solid black;text-align:center;\"><span style=\"text-decoration:underline;\"> ?? </span></td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">78,650</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">78,650</td></tr></table></div> <br/> What is the value of Dalandi Bako's capital?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦78,650</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦60,650</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦60,150</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦50,160</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The capital is calculated as the difference between total assets and total liabilities. Therefore, the correct answer is ₦60,650.</div>", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : STATEMENT OF AFFAIRS"}, {"id": "objective>Accounts>2023 Model II>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The part of capital issued only at the time of liquidation of the company is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reserved capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">called-up capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">issued capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">paid-up capital</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A company may reserve a portion of its uncalled capital to be called only in the event of winding up of the company. Such uncalled amount is called 'Reserve Capital' of the company. It is available only for the creditors on winding up of the company.</div>", "topic": "COMPANY ACCOUNT : INTRODUCTION , TYPES AND KINDS OF COMPANIES"}, {"id": "objective>Accounts>2023 Model II>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is found on the credit side of a profit and loss account?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">advertising</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bank charges</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dividend received</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wages and salaries</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dividend received as as revenue i.e income or money received in trading transactions. It is credited to the profit or loss account.</div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : PROFIT OR LOSS ACCOUNT"}, {"id": "objective>Accounts>2023 Model II>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The document issued by a revenue collector as evidence of payment to a government ministry is a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">payment voucher</div>", "<div style=\"font-family:Cambria;font-size:17px;\">receipt voucher card</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stores receipt voucher</div>", "<div style=\"font-family:Cambria;font-size:17px;\">treasury receipt</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Receipt voucher are document used to acknowledge the receipt of public revenue.</div>", "topic": "PUBLIC SECTOR ACCOUNTING : SOURCES AND CLASSIFICATION OF GOVERNMENT REVENUE"}, {"id": "objective>Accounts>2023 Model II>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is used in the public sector to monitor or control government expenditure?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cash book</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cheque</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sales day book</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vote book</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The vote book is a memorandum book which is maintained by each sub-head to control and monitor government expenditure.</div>", "topic": "PUBLIC SECTOR ACCOUNTING : PURPOSE AND DIFFERENCE BETWEEN GOVERNMENT AND COMMERCIAL ACCOUNTING"}, {"id": "objective>Accounts>2023 Model II>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The authority to transfer fund from one head to another within the same organization is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">vote</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fund</div>", "<div style=\"font-family:Cambria;font-size:17px;\">virement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">warrant</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Virement warrants is used to transfer fund from one vote head to another. It is used to create a new vote head but to transfer fund within the same economic head.</div>", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES"}, {"id": "objective>Accounts>2023 Model II>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is recorded in the folio column of the journal?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">all credit and cash sales transactions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">amount of money posted</div>", "<div style=\"font-family:Cambria;font-size:17px;\">date of entries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">particulars of transactions</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The folio shows the page of a ledger to which a transactions is posted. It also helps in identifying where the transaction is recorded in ledger.</div>", "topic": "THE JOURNAL : MEANING AND USES OF JOURNAL"}, {"id": "objective>Accounts>2023 Model II>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Bello withdraws cash from bank to office, this is called ---------- entry</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">credit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contra</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">double</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Contra entry is an entry which is recorded to reverse or offset an entry on the other side of an account. If a debit entry is recorded in an account, it will be recorded on the credit side and vice-versa.</div>", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS"}, {"id": "objective>Accounts>2023 Model II>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The accounting system in which only one aspect of transaction is recorded is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">double entry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">original entry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">single column cash book</div>", "<div style=\"font-family:Cambria;font-size:17px;\">single entry</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The single entry system in accounting is an accounting approach under which every accounting transaction is recorded with only a single entry in the accounting records, centered on the business enterprise's results, which are shown in the statement of income of the company.</div>", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : INTRODUCTION AND ADVANTAGES"}, {"id": "objective>Accounts>2023 Model II>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The journal has the following headings <strong>except</strong></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">credit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">date</div>", "<div style=\"font-family:Cambria;font-size:17px;\">discount</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The journal has debit, credit, date, particulars and folio. It is use to show narration in which the entries are posted to the ledgers.</div>", "topic": "THE JOURNAL : MEANING AND USES OF JOURNAL"}, {"id": "objective>Accounts>2023 Model II>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following has the ultimate control of a company?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">board of directors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">employees</div>", "<div style=\"font-family:Cambria;font-size:17px;\">management</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shareholders</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The ultimate controller, refers to the shareholder who has the ultimate control in the company and is not controlled by anyone. This ownership structure often results in a certain level of control between the ultimate controller and the listed company.</div>", "topic": "COMPANY ACCOUNT : INTRODUCTION , TYPES AND KINDS OF COMPANIES"}, {"id": "objective>Accounts>2023 Model II>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the dissolution of a partnership, which of the following is the correct order of settling the claims of creditors and partners?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> Pay off partners' loans, then settle external creditors, and finally distribute remaining assets to partners.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Settle external creditors first, then pay off partners' loans, and finally distribute remaining assets to partners.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Distribute remaining assets to partners first, then pay off partners' loans, and finally settle external creditors.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pay off external creditors and partners' loans simultaneously, then distribute remaining assets to partners.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the dissolution of a partnership, the correct order is to first settle external creditors to ensure that all debts owed to outside parties are cleared. After external creditors are paid, any remaining assets can then be used to pay off partners' loans. Finally, any leftover assets are distributed among the partners based on their profit-sharing ratios. This order is crucial to ensure that all obligations are met before any distribution to partners occurs.</div>", "topic": "DISSOLUTION OF PARTNERSHIP ACCOUNT : INTRODUCTION AND RULES FOR DISTRIBUTING OF ASSSETS"}];
